1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE = 25;
3	const BLOCK_OF_THREE_BASE = 60;
4	
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const FIRST_INSURANCE_RATE = 0.1;
9	const LOYALTY_DISCOUNT_RATE = 0.2;
10	const LOYALTY_YEARS_THRESHOLD = 2;
11	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
12	
13	const DEDUCTIBLE = 100;
14	const CAP_MULTIPLIER = 2;
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	};
22	
23	const INSURANCE_VALUES: Record<string, number> = {
24	  sword: 1000,
25	  amulet: 600,
26	  staff: 800,
27	  potion: 400,
28	  rune: 250,
29	  moonstone: 250,
30	};
31	
32	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
33	
34	type Item = {
35	  type: string;
36	  material?: string;
37	  enchantment?: number;
38	  cursed?: boolean;
39	};
40	type QuoteStep = { op: "quote"; items: Item[] };
41	type Damage = { itemType: string; amount: number };
42	type Incident = { cause: string; damages: Damage[] };
43	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
44	type Step = QuoteStep | ClaimStep;
45	type Customer = { yearsWithMHPCO: number };
46	type Scenario = { customer: Customer; steps: Step[] };
47	type QuoteResult = { premium: number };
48	type ClaimResult = { payout: number; remainingCap: number };
49	type StepResult = QuoteResult | ClaimResult;
50	type ScenarioResult = { results: StepResult[] };
51	
52	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
53	
54	const isKnownType = (item: Item): boolean =>
55	  item.type in BASE_PREMIUMS || COMPONENT_TYPES.has(item.type);
56	
57	const validateItems = (items: Item[]): void => {
58	  for (const item of items) {
59	    if (!isKnownType(item)) {
60	      throw new Error(`Unknown item type: ${item.type}`);
61	    }
62	  }
63	};
64	
65	const countByType = (items: Item[]): Map<string, number> => {
66	  const counts = new Map<string, number>();
67	  for (const item of items) {
68	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
69	  }
70	  return counts;
71	};
72	
73	const componentTypeBase = (count: number): number =>
74	  count === 3 ? BLOCK_OF_THREE_BASE : count * COMPONENT_BASE;
75	
76	const sum = (values: number[]): number => values.reduce((a, b) => a + b, 0);
77	
78	const mainItemBase = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
79	
80	const mainItemSurcharge = (item: Item): number => {
81	  const base = mainItemBase(item);
82	  const cursed = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
83	  const highEnch =
84	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_RATE : 0;
85	  return cursed + highEnch;
86	};
87	
88	const mainItemsBase = (mainItems: Item[]): number => sum(mainItems.map(mainItemBase));
89	
90	const componentsBase = (components: Item[]): number => {
91	  const counts = countByType(components);
92	  return sum([...counts.values()].map(componentTypeBase));
93	};
94	
95	const itemSurcharges = (mainItems: Item[]): number => sum(mainItems.map(mainItemSurcharge));
96	
97	const policyBase = (mainItems: Item[], components: Item[]): number =>
98	  mainItemsBase(mainItems) + componentsBase(components);
99	
100	const loyaltyDiscount = (base: number, customer: Customer): number =>
101	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? base * LOYALTY_DISCOUNT_RATE : 0;
102	
103	const insuranceSum = (items: Item[]): number =>
104	  sum(items.map((item) => INSURANCE_VALUES[item.type] ?? 0));
105	
106	type Policy = { items: Item[]; cap: number };
107	
108	const quote = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { result: QuoteResult; policy: Policy } => {
109	  validateItems(step.items);
110	  const mainItems = step.items.filter((item) => !isComponent(item));
111	  const components = step.items.filter(isComponent);
112	  const base = policyBase(mainItems, components);
113	  const surcharges = itemSurcharges(mainItems);
114	  const firstInsurance = base * FIRST_INSURANCE_RATE;
115	  const loyalty = loyaltyDiscount(base, customer);
116	  const followUp = isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
117	  const premium = Math.ceil(base + surcharges + firstInsurance - loyalty - followUp + PROCESSING_FEE);
118	  const cap = insuranceSum(step.items) * CAP_MULTIPLIER;
119	  return { result: { premium }, policy: { items: step.items, cap } };
120	};
121	
122	const claim = (step: ClaimStep, policy: Policy): ClaimResult => {
123	  const totalPayout = sum(step.incident.damages.map((d) => d.amount - DEDUCTIBLE));
124	  return { payout: totalPayout, remainingCap: policy.cap - totalPayout };
125	};
