127	export const runScenario = (scenario: Scenario): ScenarioResult => {
128	  const policies: Policy[] = [];
129	  const results: StepResult[] = [];
130	  let quoteCount = 0;
131	  for (const step of scenario.steps) {
132	    if (step.op === "quote") {
133	      const { result, policy } = quote(step, scenario.customer, quoteCount > 0);
134	      policies.push(policy);
135	      results.push(result);
136	      quoteCount++;
137	    } else {
138	      results.push(claim(step, policies[step.policy]));
139	    }
140	  }
141	  return { results };
142	};
